const q = $.input.question.toLowerCase();
const needsSearch = !(/^(what is|calculate|compute|how much is|solve|evaluate)\s+[\d+\-*/().^%\s]+$/i.test($.input.question));
const searchQuery = $.input.question;
return { needsSearch, searchQuery };

const results = $.steps.webSearch.response.results || [];

let sourcesText = '';
results.forEach((r, i) => {
  sourcesText += (i+1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1000) + '\n\n';
});

return { sourcesText, sourceCount: results.length };

const prompt = `You are a helpful AI agent that can search the web and perform calculations. Answer the user's question thoughtfully.

USER QUESTION: ${$.input.question}

WEB SEARCH CONTEXT (${$.steps.compileSources.output.sourceCount} sources):
${$.steps.compileSources.output.sourcesText}

INSTRUCTIONS:
- If the question involves math or calculations, show your work step by step
- If it requires factual information, synthesize from the search results and cite sources [1], [2], etc.
- If it's a general knowledge question, combine your knowledge with the search results
- Be conversational, helpful, and clear
- Use Slack mrkdwn formatting: *bold* (NOT **bold**), _italic_, numbered lists. No markdown tables. No # headings.

Return ONLY valid JSON:
{
  "answer": "<your comprehensive answer using Slack mrkdwn>",
  "reasoning": "<brief explanation of how you arrived at the answer>",
  "tools_used": ["web_search", "calculation"],
  "follow_up_suggestions": ["<suggestion 1>", "<suggestion 2>"]
}`;

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, reasoning: '', tools_used: ['web_search'], follow_up_suggestions: [] }; }

const ai = $.steps.parseAI.output || {};
const question = $.input.question;

const toolIcons = (ai.tools_used || []).map(t => t === 'web_search' ? ':mag:' : t === 'calculation' ? ':abacus:' : ':gear:').join(' ');

const blocks = [];

blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Agent Response' } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answerText } });

if (ai.reasoning) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Reasoning:* ' + ai.reasoning.slice(0, 1000) } });
}

if (ai.follow_up_suggestions && ai.follow_up_suggestions.length > 0) {
  blocks.push({ type: 'divider' });
  let suggestions = '*Try asking next:*\n';
  ai.follow_up_suggestions.forEach((s, i) => { suggestions += (i+1) + '. ' + s + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: suggestions } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: toolIcons + ' Tools used: ' + (ai.tools_used || []).join(', ') + ' | Sources: ' + $.steps.compileSources.output.sourceCount }] });

const fallback = 'AI Agent answer to: ' + question;

return { blocks, fallback };
